head.script:
/**
 * 화 면 명 : 인장이미지보기
 * 메뉴경로 : 공통/총무업무/인장관리/인장등록
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/cm/bc/sealmgnt/zz_914_01_00p.jsp
 * 작 성 자 : 정승혜
 * 작 업 일 : 2025-12-04
 * 수정이력  :
 *    - 2025-12-04      정승혜    최초작성
 *    - 2026-03-18      정승혜    기타수정
 * 메모 : 
 * 조회조건 : 
 */
scwin.params = "";

scwin.sealOwner = "";
scwin.sealOwnerNm = "";
scwin.sealKind = "";
scwin.sealKindNm = "";
scwin.sealStDt = "";

scwin.onpageload = function() {

    scwin.params = $c.data.getParameter();

    scwin.sealOwner = scwin.params["sealOwner"]
    scwin.sealOwnerNm = scwin.params["sealOwnerNm"]
    scwin.sealKind = scwin.params["sealKind"]
    scwin.sealKindNm = scwin.params["sealKindNm"]
    scwin.sealStDt = scwin.params["sealStDt"]

	console.log("params : " + JSON.stringify(scwin.params));
    scwin.f_image();
};

scwin.f_Close = function() {
    $c.win.closePopup();
};

scwin.f_image = function() {
    var imageUrl = $c.sbm.getContextPath() + "/cm.bc.sealmgnt.RetrieveSealImage.do"
        + "?sealOwner=" + encodeURIComponent(scwin.sealOwner || "")
        + "&sealKind=" + encodeURIComponent(scwin.sealKind || "")
        + "&sealStDt=" + encodeURIComponent(scwin.sealStDt || "");

    img_image1.setSrc(imageUrl);
};
